  1→/* ═══════════════════════════════════════════════════
  2→   ANIMATIONS & TRANSITIONS — v6
  3→   Principle: fast-in, slow-out. Spring for pops.
  4→   Reduce motion respected throughout.
  5→   ═══════════════════════════════════════════════════ */
  6→
  7→@media (prefers-reduced-motion: reduce) {
  8→  *, *::before, *::after {
  9→    animation-duration: 0.01ms !important;
 10→    transition-duration: 0.01ms !important;
 11→  }
 12→}
 13→
 14→/* ── Core keyframes ──────────────────────────────── */
 15→@keyframes fadeIn {
 16→  from { opacity: 0; }
 17→  to   { opacity: 1; }
 18→}
 19→@keyframes fadeSlideDown {
 20→  from { opacity: 0; transform: translate3d(0, -8px, 0); }
 21→  to   { opacity: 1; transform: translate3d(0, 0, 0); }
 22→}
 23→@keyframes fadeSlideUp {
 24→  from { opacity: 0; transform: translate3d(0, 10px, 0); }
 25→  to   { opacity: 1; transform: translate3d(0, 0, 0); }
 26→}
 27→@keyframes scaleIn {
 28→  from { opacity: 0; transform: scale(0.94) translate3d(0, 8px, 0); }
 29→  to   { opacity: 1; transform: scale(1) translate3d(0, 0, 0); }
 30→}
 31→@keyframes springIn {
 32→  from { opacity: 0; transform: scale(0.90) translate3d(0, 14px, 0); }
 33→  to   { opacity: 1; transform: scale(1) translate3d(0, 0, 0); }
 34→}
 35→@keyframes slideLoader {
 36→  0%   { transform: translateX(-100%); }
 37→  100% { transform: translateX(350%); }
 38→}
 39→@keyframes spin {
 40→  to { transform: rotate(360deg); }
 41→}
 42→@keyframes pulse {
 43→  0%,100% { opacity: 1; }
 44→  50%     { opacity: 0.2; }
 45→}
 46→@keyframes bounce {
 47→  0%,100% { transform: translateY(0); }
 48→  50%     { transform: translateY(-4px); }
 49→}
 50→@keyframes float {
 51→  0%,100% { transform: translateY(0); }
 52→  50%     { transform: translateY(-5px); }
 53→}
 54→@keyframes shake {
 55→  0%,100% { transform: translateX(0); }
 56→  20%     { transform: translateX(-4px); }
 57→  60%     { transform: translateX(4px); }
 58→  80%     { transform: translateX(-2px); }
 59→}
 60→@keyframes pop {
 61→  0%   { transform: scale(1); }
 62→  40%  { transform: scale(1.1); }
 63→  100% { transform: scale(1); }
 64→}
 65→@keyframes tickIn {
 66→  from { opacity: 0; transform: scale(0.4); }
 67→  to   { opacity: 1; transform: scale(1); }
 68→}
 69→@keyframes dotPulse {
 70→  0%,100% { box-shadow: 0 0 4px var(--win); }
 71→  50%     { box-shadow: 0 0 10px var(--win), 0 0 18px var(--win); }
 72→}
 73→@keyframes expandDown {
 74→  from { opacity: 0; transform: scaleY(0.95); transform-origin: top; }
 75→  to   { opacity: 1; transform: scaleY(1); transform-origin: top; }
 76→}
 77→@keyframes barGrow {
 78→  from { width: 0; }
 79→}
 80→
 81→/* ── Splash screen — premium loading ─────────────── */
 82→.splash-screen {
 83→  min-height: 100vh;
 84→  display: flex; flex-direction: column;
 85→  align-items: center; justify-content: center;
 86→  gap: var(--sp-4);
 87→  animation: fadeIn 0.25s var(--ease) both;
 88→  background:
 89→    radial-gradient(ellipse at 50% 40%, oklch(14% 0.030 280 / 0.5) 0%, transparent 50%),
 90→    radial-gradient(ellipse at 30% 70%, oklch(12% 0.020 250 / 0.3) 0%, transparent 50%),
 91→    var(--bg);
 92→}
 93→.splash-logo {
 94→  font-size: 56px;
 95→  animation: float 2.5s var(--ease-out-quint) infinite;
 96→  filter: drop-shadow(0 6px 16px oklch(0% 0 0 / 0.4));
 97→}
 98→.splash-title {
 99→  font-family: var(--font-display);
100→  font-weight: var(--weight-black); font-size: var(--text-3xl);
101→  background: var(--gradient-accent);
102→  -webkit-background-clip: text;
103→  -webkit-text-fill-color: transparent;
104→  background-clip: text;
105→  letter-spacing: -0.5px;
106→  animation: fadeSlideUp 0.4s var(--ease) 0.1s both;
107→}
108→.splash-loader {
109→  width: 120px; height: 2px;
110→  background: var(--border2);
111→  border-radius: var(--radius-full); overflow: hidden;
112→  margin-top: var(--sp-3);
113→  animation: fadeIn 0.4s var(--ease) 0.2s both;
114→}
115→.splash-bar {
116→  height: 100%; width: 40%;
117→  background: linear-gradient(90deg, var(--accent), oklch(74% 0.18 280 / 0.6));
118→  border-radius: var(--radius-full);
119→  animation: slideLoader 1.1s var(--ease) infinite;
120→}
121→
122→/* ── Tab transitions ─────────────────────────────── */
123→.tab-enter   {
124→  animation: fadeSlideUp 0.15s var(--ease) both;
125→}
126→.tab-exit    {
127→  opacity: 0;
128→  transform: translateY(4px);
129→  transition: opacity 0.1s var(--ease), transform 0.1s var(--ease);
130→  pointer-events: none;
131→}
132→
133→/* ── Page intro ──────────────────────────────────── */
134→.page-intro { animation: fadeSlideDown 0.15s var(--ease) both; }
135→
136→/* ── Cards ───────────────────────────────────────── */
137→.card { animation: fadeSlideUp 0.15s var(--ease) both; }
138→
139→.task-card { animation: fadeSlideUp 0.15s var(--ease) both; }
140→.task-card:nth-child(1) { animation-delay: 0.01s; }
141→.task-card:nth-child(2) { animation-delay: 0.03s; }
142→.task-card:nth-child(3) { animation-delay: 0.05s; }
143→
144→/* ── Buttons ─────────────────────────────────────── */
145→.btn-primary, .btn-success, .btn-secondary {
146→  transition:
147→    opacity var(--t-fast) var(--ease),
148→    transform var(--t-fast) var(--ease),
149→    box-shadow var(--t-base) var(--ease),
150→    background var(--t-base) var(--ease),
151→    border-color var(--t-base) var(--ease);
152→}
153→.done-btn {
154→  transition: all var(--t-base) var(--ease);
155→}
156→.done-btn:active     { transform: scale(0.94); }
157→.done-btn-active     { animation: pop 0.22s var(--ease-out-quint) both; }
158→
159→/* ── Outcome cards ───────────────────────────────── */
160→.outcome-card {
161→  transition: transform var(--t-fast) var(--ease),
162→              border-color var(--t-base) var(--ease),
163→              background var(--t-base) var(--ease),
164→              box-shadow var(--t-base) var(--ease);
165→}
166→.outcome-card:hover  { transform: translateY(-2px); }
167→.outcome-card:active { transform: scale(0.97); }
168→.outcome-card:nth-child(1) { animation: fadeSlideUp 0.15s var(--ease) 0.00s both; }
169→.outcome-card:nth-child(2) { animation: fadeSlideUp 0.15s var(--ease) 0.02s both; }
170→.outcome-card:nth-child(3) { animation: fadeSlideUp 0.15s var(--ease) 0.04s both; }
171→
172→/* ── Checkbox ────────────────────────────────────── */
173→.check-box.done::after { animation: tickIn 0.14s var(--ease-out-quint) both; }
174→
175→/* ── Sliders ─────────────────────────────────────── */
176→.energy-slider::-webkit-slider-thumb {
177→  transition: transform 0.14s var(--ease), box-shadow 0.14s var(--ease);
178→}
179→.energy-slider:hover::-webkit-slider-thumb,
180→.energy-slider:active::-webkit-slider-thumb {
181→  transform: scale(1.25);
182→  box-shadow: 0 0 0 7px oklch(74% 0.18 280 / 0.12);
183→}
184→
185→/* ── Tab button active bar ───────────────────────── */
186→.tab-btn::after {
187→  content: '';
188→  display: block;
189→  height: 2px; width: 0;
190→  background: var(--accent);
191→  border-radius: 1px;
192→  margin-top: 3px;
193→  transition: width var(--t-base) var(--ease);
194→}
195→.tab-btn-active::after { width: 100%; }
196→
197→/* ── Macro/progress bars ─────────────────────────── */
198→.nutr-macro-bar-fill,
199→.dash-today-bar-fill {
200→  animation: barGrow 0.5s var(--ease) both;
201→}
202→
203→/* ── Daily status bar — premium ──────────────────── */
204→.daily-status {
205→  display: flex; align-items: center; gap: 12px;
206→  padding: 11px 18px;
207→  font-size: 12px; cursor: pointer;
208→  border-bottom: 1px solid oklch(18% 0.008 260);
209→  transition: background var(--t-fast) var(--ease);
210→  animation: fadeSlideDown 0.15s var(--ease) both;
211→  position: relative;
212→}
213→.daily-status::before {
214→  content: '';
215→  position: absolute;
216→  inset: 0;
217→  background: linear-gradient(90deg, transparent, oklch(94% 0.006 260 / 0.015), transparent);
218→  pointer-events: none;
219→  opacity: 0;
220→  transition: opacity var(--t-base) var(--ease);
221→}
222→.daily-status:hover::before { opacity: 1; }
223→.daily-status-active { background: oklch(74% 0.18 280 / 0.04) !important; }
224→.daily-status-done    { color: var(--win); }
225→.daily-status-morning { color: var(--work); }
226→.daily-status-night   { color: var(--body); }
227→.daily-status-urgent  { color: var(--miss); }
228→.ds-icon  { font-size: 16px; flex-shrink: 0; }
229→.ds-text  { flex: 1; line-height: 1.35; }
230→.ds-message { font-size: 12px; color: var(--text); }
231→.ds-message strong { font-weight: 600; }
232→.ds-sub { font-size: 10px; color: var(--muted2); margin-top: 2px; }
233→.ds-right { display: flex; align-items: center; gap: 10px; flex-shrink: 0; }
234→.ds-dots  { display: flex; gap: 5px; }
235→.ds-dot   {
236→  width: 7px; height: 7px; border-radius: 50%;
237→  background: oklch(22% 0.008 260);
238→  transition: background var(--t-base) var(--ease), transform var(--t-base) var(--ease), box-shadow var(--t-base) var(--ease);
239→}
240→.ds-dot-done { transform: scale(1.2); box-shadow: 0 0 6px currentColor; }
241→.ds-arrow { font-size: 13px; opacity: 0.3; flex-shrink: 0; transition: transform var(--t-base) var(--ease), opacity var(--t-base) var(--ease); }
242→.daily-status:hover .ds-arrow { transform: translateX(5px); opacity: 0.8; }
243→
244→/* ── Onboarding — premium feel ──────────────────── */
245→.onboard-gate {
246→  min-height: 100vh;
247→  display: flex; align-items: center; justify-content: center;
248→  padding: var(--sp-6);
249→  background:
250→    radial-gradient(ellipse at 30% 20%, oklch(14% 0.030 280 / 0.5) 0%, transparent 50%),
251→    radial-gradient(ellipse at 70% 80%, oklch(12% 0.025 250 / 0.4) 0%, transparent 50%),
252→    var(--bg);
253→}
254→.onboard-card {
255→  background: var(--gradient-surface);
256→  border: 1px solid oklch(22% 0.010 260);
257→  border-radius: var(--radius-xl);
258→  padding: var(--sp-12) var(--sp-8) var(--sp-8);
259→  width: 100%; max-width: 380px;
260→  text-align: center;
261→  box-shadow: var(--shadow-lg);
262→  position: relative;
263→  overflow: hidden;
264→}
265→.onboard-card::before {
266→  content: '';
267→  position: absolute;
268→  top: 0; left: 0; right: 0;
269→  height: 3px;
270→  background: linear-gradient(90deg, var(--work), var(--accent), var(--body));
271→}
272→.onboard-card::after {
273→  content: '';
274→  position: absolute;
275→  inset: 0;
276→  background: radial-gradient(circle at 50% 0%, oklch(94% 0.006 260 / 0.03) 0%, transparent 60%);
277→  pointer-events: none;
278→}
279→.onboard-enter { animation: springIn 0.4s var(--ease-out-quint) both; }
280→.onboard-exit  { animation: scaleIn 0.2s var(--ease) reverse both; }
281→.onboard-emoji {
282→  font-size: 56px; margin-bottom: var(--sp-5); display: block;
283→  animation: float 3.5s var(--ease) infinite;
284→  filter: drop-shadow(0 4px 12px oklch(0% 0 0 / 0.3));
285→}
286→.onboard-title {
287→  font-family: var(--font-display);
288→  font-weight: var(--weight-black); font-size: var(--text-2xl);
289→  background: var(--gradient-accent);
290→  -webkit-background-clip: text;
291→  -webkit-text-fill-color: transparent;
292→  background-clip: text;
293→  margin-bottom: var(--sp-1);
294→  letter-spacing: -0.3px;
295→}
296→.onboard-sub {
297→  font-size: var(--text-sm); color: var(--muted2);
298→  letter-spacing: 0.5px; margin-bottom: var(--sp-5);
299→}
300→.onboard-body {
301→  font-size: var(--text-base); color: var(--text);
302→  line-height: 1.7; margin-bottom: var(--sp-8);
303→}
304→.onboard-btn { width: 100%; margin-bottom: var(--sp-5); }
305→.onboard-dots { display: flex; justify-content: center; gap: var(--sp-2); margin-bottom: var(--sp-3); }
306→.onboard-dot {
307→  width: 7px; height: 7px; border-radius: 50%;
308→  background: oklch(22% 0.008 260);
309→  transition: all var(--t-base) var(--ease-out-quint);
310→}
311→.onboard-dot-active {
312→  background: var(--accent);
313→  transform: scale(1.5);
314→  box-shadow: 0 0 8px oklch(74% 0.18 280 / 0.4), 0 0 16px oklch(74% 0.18 280 / 0.15);
315→}
316→.onboard-skip {
317→  background: none; border: none; font-family: var(--font-mono);
318→  font-size: var(--text-sm); color: var(--muted); cursor: pointer;
319→  transition: color var(--t-base) var(--ease);
320→}
321→.onboard-skip:hover { color: var(--muted2); }
322→
323→/* ── Modal ───────────────────────────────────────── */
324→.modal-overlay { animation: fadeIn 0.12s var(--ease) both; }
325→.modal         { animation: scaleIn 0.15s var(--ease-out-quint) both; }
326→
327→/* ── Banners ─────────────────────────────────────── */
328→.yesterday-banner { animation: fadeSlideDown 0.18s var(--ease) 0.04s both; opacity: 0; animation-fill-mode: forwards; }
329→.info-banner      { animation: fadeSlideDown 0.15s var(--ease) both; }
330→.warning-banner   { animation: fadeSlideUp 0.15s var(--ease) both, shake 0.3s var(--ease) 0.18s; }
331→.streak-banner    { animation: springIn 0.25s var(--ease-out-quint) both; }
332→.nutr-nudge-banner { animation: fadeSlideDown 0.18s var(--ease) both; }
333→
334→/* ── Toast — polished notification ───────────────── */
335→.toast {
336→  position: fixed; bottom: 28px; left: 50%;
337→  transform: translateX(-50%) translateY(14px) scale(0.95);
338→  padding: var(--sp-3) var(--sp-6);
339→  border-radius: var(--radius-full);
340→  font-family: var(--font-mono); font-size: var(--text-sm);
341→  font-weight: var(--weight-medium);
342→  opacity: 0;
343→  transition: opacity var(--t-slow) var(--ease-out-quint),
344→              transform var(--t-slow) var(--ease-out-quint);
345→  pointer-events: none; white-space: nowrap; z-index: 999;
346→}
347→.toast-ok {
348→  background: oklch(74% 0.16 160 / 0.95);
349→  color: oklch(8% 0.012 260);
350→  box-shadow: 0 4px 12px oklch(74% 0.16 160 / 0.25), 0 12px 32px oklch(74% 0.16 160 / 0.15), inset 0 1px 0 oklch(100% 0 0 / 0.15);
351→}
352→.toast-err {
353→  background: oklch(64% 0.22 25 / 0.95);
354→  color: oklch(94% 0.006 260);
355→  box-shadow: 0 4px 12px oklch(64% 0.22 25 / 0.25), 0 12px 32px oklch(64% 0.22 25 / 0.15), inset 0 1px 0 oklch(100% 0 0 / 0.1);
356→}
357→.toast-show {
358→  opacity: 1;
359→  transform: translateX(-50%) translateY(0) scale(1);
360→}
361→
362→/* ── Week expand ─────────────────────────────────── */
363→.week-expand { animation: expandDown 0.22s var(--ease) both; overflow: hidden; }
364→
365→/* ── Stat cards ──────────────────────────────────── */
366→.stat-card { animation: fadeSlideUp 0.15s var(--ease) both; }
367→.stats-grid .stat-card:nth-child(1) { animation-delay: 0.00s; }
368→.stats-grid .stat-card:nth-child(2) { animation-delay: 0.02s; }
369→.stats-grid .stat-card:nth-child(3) { animation-delay: 0.04s; }
370→.stats-grid .stat-card:nth-child(4) { animation-delay: 0.06s; }
371→
372→/* ── Chart ───────────────────────────────────────── */
373→.chart-header { animation: fadeIn 0.2s var(--ease) 0.05s both; }
374→
375→/* ── Empty state ─────────────────────────────────── */
376→.empty-state {
377→  animation: fadeIn 0.2s var(--ease) 0.05s both;
378→  opacity: 0; animation-fill-mode: forwards;
379→}
380→
381→/* ── Server dot ──────────────────────────────────── */
382→.server-ok .server-dot { animation: dotPulse 2.8s var(--ease) infinite; }
383→
384→/* ── Score badge ─────────────────────────────────── */
385→.score-badge { transition: background var(--t-base) var(--ease), color var(--t-base) var(--ease); }
386→
387→/* ── Spinner ─────────────────────────────────────── */
388→.spinner {
389→  width: 13px; height: 13px;
390→  border: 2px solid oklch(8% 0.012 260 / 0.25);
391→  border-top-color: oklch(8% 0.012 260);
392→  border-radius: 50%;
393→  animation: spin 0.55s linear infinite;
394→  display: none;
395→}
396→.spinner.show { display: inline-block; }
397→
398→/* ── Sync spinner (see index.css for base style) ── */
399→
400→/* ── Help rhythm dots ────────────────────────────── */
401→.help-rhythm-dot { transition: box-shadow var(--t-base) var(--ease); }
402→
403→/* ── Prof goal button ────────────────────────────── */
404→.prof-goal-btn {
405→  transition: border-color var(--t-base) var(--ease),
406→              background var(--t-base) var(--ease),
407→              color var(--t-base) var(--ease),
408→              transform var(--t-fast) var(--ease);
409→}
410→.prof-goal-btn:active { transform: scale(0.96); }
411→
412→/* ── TDEE card ───────────────────────────────────── */
413→.prof-tdee-card { animation: fadeSlideUp 0.25s var(--ease-out-quint) both; }
414→
415→/* ── Nutr confirm form ───────────────────────────── */
416→.nutr-image-preview { animation: scaleIn 0.22s var(--ease-out-quint) both; }
417→.nutr-impact-card   { animation: fadeSlideUp 0.22s var(--ease) both; }
418→
419→/* ── Achievement popup ───────────────────────────── */
420→.achievement-popup { animation: springIn 0.35s var(--ease-out-quint) both; }
421→
422→/* ── Coach loading dots ──────────────────────────── */
423→.coach-loading-dots div {
424→  animation: bounce 1.1s var(--ease) infinite;
425→}
426→.coach-loading-dots div:nth-child(2) { animation-delay: 0.15s; }
427→.coach-loading-dots div:nth-child(3) { animation-delay: 0.30s; }
428→
429→/* ── Dashboard today steps ───────────────────────── */
430→.dash-today-step {
431→  transition: background var(--t-base) var(--ease);
432→  border-radius: var(--radius-sm);
433→}
434→.dash-today-step:hover { background: oklch(94% 0.006 260 / 0.04); }
435→
436→/* ── Nutr macro bar fill ─────────────────────────── */
437→.nutr-macro-bar-fill {
438→  transition: width 0.5s var(--ease);
439→  animation: barGrow 0.5s var(--ease) both;
440→}
441→
442→/* ── Confetti celebration ───────────────────────── */
443→@keyframes confettiFall {
444→  0%   { transform: translateY(-10vh) rotate(0deg); opacity: 1; }
445→  80%  { opacity: 1; }
446→  100% { transform: translateY(105vh) rotate(720deg); opacity: 0; }
447→}
448→.confetti-container {
449→  position: fixed; inset: 0;
450→  pointer-events: none; z-index: 1000;
451→  overflow: hidden;
452→}
453→.confetti-particle {
454→  position: absolute; top: -8px;
455→  width: 8px; height: 12px;
456→  border-radius: 2px;
457→  animation: confettiFall 2s var(--ease) forwards;
458→}

